"use strict";(self.webpackChunkadvance_import_export_woocommerce=self.webpackChunkadvance_import_export_woocommerce||[]).push([[8468],{9762(e,a,s){s.r(a),s.d(a,{comp:()=>l,data:()=>r});var t=s(641);const n={},l=(0,s(6262).A)(n,[["render",function(e,a){const s=(0,t.g2)("RouteLink");return(0,t.uX)(),(0,t.CE)("div",null,[a[6]||(a[6]=(0,t.Fv)('<h1 id="categories-and-tags-import" tabindex="-1"><a class="header-anchor" href="#categories-and-tags-import"><span>Categories and Tags Import</span></a></h1><p>Import product categories (with parent-child hierarchy), tags, and attributes.</p><p><img src="/advance-import-export-woocommerce/images/wizard-step-1.webp" alt="Quick Import wizard step 1 — upload and configure"><em>Step 1 of the Quick Import wizard: select Categories, Tags, or Attributes and upload your taxonomy file.</em></p><h2 id="three-related-entity-types" tabindex="-1"><a class="header-anchor" href="#three-related-entity-types"><span>Three Related Entity Types</span></a></h2><table><thead><tr><th>Entity</th><th>What It Is</th></tr></thead><tbody><tr><td><strong>Categories</strong></td><td>Product categories (hierarchical, e.g., Clothing &gt; Men&#39;s &gt; Shirts)</td></tr><tr><td><strong>Tags</strong></td><td>Product tags (flat, e.g., summer, cotton, sale)</td></tr><tr><td><strong>Attributes</strong></td><td>Attribute definitions (Color, Size, Material) and their values (Red, Small, Cotton)</td></tr></tbody></table><h2 id="categories" tabindex="-1"><a class="header-anchor" href="#categories"><span>Categories</span></a></h2><h3 id="column-reference" tabindex="-1"><a class="header-anchor" href="#column-reference"><span>Column Reference</span></a></h3><table><thead><tr><th>Column</th><th style="text-align:center;">Required</th><th>Example</th></tr></thead><tbody><tr><td><code>Name</code></td><td style="text-align:center;">Yes</td><td><code>Men&#39;s T-Shirts</code></td></tr><tr><td><code>Slug</code></td><td style="text-align:center;">No</td><td><code>mens-t-shirts</code></td></tr><tr><td><code>Description</code></td><td style="text-align:center;">No</td><td><code>Premium men&#39;s t-shirts</code></td></tr><tr><td><code>Parent</code></td><td style="text-align:center;">No</td><td><code>Men&#39;s</code> (parent name) or <code>42</code> (parent ID)</td></tr><tr><td><code>Image URL</code></td><td style="text-align:center;">No</td><td><code>https://example.com/mens-tshirts.jpg</code></td></tr><tr><td><code>Display Type</code></td><td style="text-align:center;">No</td><td><code>default</code>, <code>products</code>, <code>subcategories</code>, <code>both</code></td></tr><tr><td><code>Sort Order</code></td><td style="text-align:center;">No</td><td><code>1</code>, <code>2</code>, <code>3</code></td></tr></tbody></table><h3 id="full-path-in-one-column" tabindex="-1"><a class="header-anchor" href="#full-path-in-one-column"><span>Full Path in One Column</span></a></h3><p>Instead of using a <code>Parent</code> column, use the full path:</p><div class="language-csv line-numbers-mode" data-highlighter="prismjs" data-ext="csv"><pre><code><span class="line"><span class="token value">Name</span></span>\n<span class="line"><span class="token value">Clothing &gt; Men&#39;s &gt; T-Shirts</span></span>\n<span class="line"><span class="token value">Clothing &gt; Men&#39;s &gt; Pants</span></span>\n<span class="line"><span class="token value">Clothing &gt; Women&#39;s &gt; Dresses</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Plugin creates all parent categories automatically.</p><h3 id="change-the-separator" tabindex="-1"><a class="header-anchor" href="#change-the-separator"><span>Change the Separator</span></a></h3><p>Default is <code>&gt;</code>. Change in wizard → Step 2 → Separators.</p><h3 id="auto-create-missing-parents" tabindex="-1"><a class="header-anchor" href="#auto-create-missing-parents"><span>Auto-Create Missing Parents</span></a></h3><p>If you import <code>Clothing &gt; Men&#39;s &gt; T-Shirts</code> but <code>Clothing</code> and <code>Men&#39;s</code> do not exist yet, the plugin creates them automatically.</p><p>You never need to create parents first.</p><h2 id="tags" tabindex="-1"><a class="header-anchor" href="#tags"><span>Tags</span></a></h2><p>Tags are flat. No hierarchy.</p><h3 id="column-reference-1" tabindex="-1"><a class="header-anchor" href="#column-reference-1"><span>Column Reference</span></a></h3><table><thead><tr><th>Column</th><th style="text-align:center;">Required</th><th>Example</th></tr></thead><tbody><tr><td><code>Name</code></td><td style="text-align:center;">Yes</td><td><code>summer</code></td></tr><tr><td><code>Slug</code></td><td style="text-align:center;">No</td><td><code>summer-collection</code></td></tr><tr><td><code>Description</code></td><td style="text-align:center;">No</td><td><code>Summer 2026 collection</code></td></tr></tbody></table><h3 id="multiple-tags-per-product" tabindex="-1"><a class="header-anchor" href="#multiple-tags-per-product"><span>Multiple Tags per Product</span></a></h3><p>When importing products, use a comma-separated list:</p><div class="language-csv line-numbers-mode" data-highlighter="prismjs" data-ext="csv"><pre><code><span class="line"><span class="token value">SKU</span><span class="token punctuation">,</span><span class="token value">Name</span><span class="token punctuation">,</span><span class="token value">Tags</span></span>\n<span class="line"><span class="token value">WK-001</span><span class="token punctuation">,</span><span class="token value">Cotton Tee</span><span class="token punctuation">,</span><span class="token value">&quot;cotton, summer, casual&quot;</span></span>\n<span class="line"><span class="token value">WK-002</span><span class="token punctuation">,</span><span class="token value">Denim Jeans</span><span class="token punctuation">,</span><span class="token value">&quot;denim, casual, men&quot;</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Tags that do not exist are auto-created.</p><h2 id="attributes" tabindex="-1"><a class="header-anchor" href="#attributes"><span>Attributes</span></a></h2><p>Attributes are more complex. They have:</p><ul><li><strong>Name</strong> (e.g., Color)</li><li><strong>Slug</strong> (e.g., pa_color)</li><li><strong>Terms</strong> (the actual values: Red, Blue, Green)</li></ul><h3 id="creating-attributes" tabindex="-1"><a class="header-anchor" href="#creating-attributes"><span>Creating Attributes</span></a></h3><p>Create the attribute first, then add terms.</p><h4 id="attribute-import-file" tabindex="-1"><a class="header-anchor" href="#attribute-import-file"><span>Attribute Import File</span></a></h4><div class="language-csv line-numbers-mode" data-highlighter="prismjs" data-ext="csv"><pre><code><span class="line"><span class="token value">Name</span><span class="token punctuation">,</span><span class="token value">Slug</span><span class="token punctuation">,</span><span class="token value">Type</span><span class="token punctuation">,</span><span class="token value">Order By</span><span class="token punctuation">,</span><span class="token value">Has Archives</span></span>\n<span class="line"><span class="token value">Color</span><span class="token punctuation">,</span><span class="token value">pa_color</span><span class="token punctuation">,</span><span class="token value">select</span><span class="token punctuation">,</span><span class="token value">menu_order</span><span class="token punctuation">,</span><span class="token value">1</span></span>\n<span class="line"><span class="token value">Size</span><span class="token punctuation">,</span><span class="token value">pa_size</span><span class="token punctuation">,</span><span class="token value">select</span><span class="token punctuation">,</span><span class="token value">menu_order</span><span class="token punctuation">,</span><span class="token value">1</span></span>\n<span class="line"><span class="token value">Material</span><span class="token punctuation">,</span><span class="token value">pa_material</span><span class="token punctuation">,</span><span class="token value">text</span><span class="token punctuation">,</span><span class="token value">name</span><span class="token punctuation">,</span><span class="token value">0</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="attribute-term-import" tabindex="-1"><a class="header-anchor" href="#attribute-term-import"><span>Attribute Term Import</span></a></h4><div class="language-csv line-numbers-mode" data-highlighter="prismjs" data-ext="csv"><pre><code><span class="line"><span class="token value">Attribute</span><span class="token punctuation">,</span><span class="token value">Term Name</span><span class="token punctuation">,</span><span class="token value">Term Slug</span><span class="token punctuation">,</span><span class="token value">Description</span></span>\n<span class="line"><span class="token value">Color</span><span class="token punctuation">,</span><span class="token value">Red</span><span class="token punctuation">,</span><span class="token value">red</span><span class="token punctuation">,</span><span class="token value">Bright red</span></span>\n<span class="line"><span class="token value">Color</span><span class="token punctuation">,</span><span class="token value">Blue</span><span class="token punctuation">,</span><span class="token value">blue</span><span class="token punctuation">,</span><span class="token value">Ocean blue</span></span>\n<span class="line"><span class="token value">Size</span><span class="token punctuation">,</span><span class="token value">Small</span><span class="token punctuation">,</span><span class="token value">s</span><span class="token punctuation">,</span></span>\n<span class="line"><span class="token value">Size</span><span class="token punctuation">,</span><span class="token value">Medium</span><span class="token punctuation">,</span><span class="token value">m</span><span class="token punctuation">,</span></span>\n<span class="line"><span class="token value">Size</span><span class="token punctuation">,</span><span class="token value">Large</span><span class="token punctuation">,</span><span class="token value">l</span><span class="token punctuation">,</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="attribute-types" tabindex="-1"><a class="header-anchor" href="#attribute-types"><span>Attribute Types</span></a></h3><table><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><code>select</code></td><td>Dropdown</td></tr><tr><td><code>text</code></td><td>Free text</td></tr></tbody></table><h3 id="order-by" tabindex="-1"><a class="header-anchor" href="#order-by"><span>Order By</span></a></h3><table><thead><tr><th>Value</th><th>What It Does</th></tr></thead><tbody><tr><td><code>menu_order</code></td><td>Use the sort order you set</td></tr><tr><td><code>name</code></td><td>Alphabetical by name</td></tr><tr><td><code>name_num</code></td><td>Alphabetical, treating numbers as numbers</td></tr><tr><td><code>id</code></td><td>Order by creation date</td></tr></tbody></table><h3 id="has-archives" tabindex="-1"><a class="header-anchor" href="#has-archives"><span>Has Archives</span></a></h3><p>Set to <code>1</code> if you want a page like <code>/pa_color/red/</code> showing all red products.</p><p><img src="/advance-import-export-woocommerce/images/wizard-step-3.webp" alt="Wizard step 3 — dry run preview with sample rows and create/update counts"><em>The dry run shows exactly which parent categories will be auto-created, which existing terms will be updated, and which rows would error.</em></p><h2 id="category-images" tabindex="-1"><a class="header-anchor" href="#category-images"><span>Category Images</span></a></h2><h3 id="upload-via-url" tabindex="-1"><a class="header-anchor" href="#upload-via-url"><span>Upload via URL</span></a></h3><div class="language-csv line-numbers-mode" data-highlighter="prismjs" data-ext="csv"><pre><code><span class="line"><span class="token value">Name</span><span class="token punctuation">,</span><span class="token value">Image URL</span></span>\n<span class="line"><span class="token value">Men&#39;s Shirts</span><span class="token punctuation">,</span><span class="token value">https://example.com/mens-shirts.jpg</span></span>\n<span class="line"><span class="token value">Women&#39;s Dresses</span><span class="token punctuation">,</span><span class="token value">https://example.com/womens-dresses.jpg</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Plugin downloads and attaches the image.</p><h3 id="re-use-media-library" tabindex="-1"><a class="header-anchor" href="#re-use-media-library"><span>Re-use Media Library</span></a></h3><p>If the image is already in your Media Library, use the attachment URL.</p><h2 id="display-types" tabindex="-1"><a class="header-anchor" href="#display-types"><span>Display Types</span></a></h2><table><thead><tr><th>Type</th><th>Example</th></tr></thead><tbody><tr><td><code>default</code></td><td>Show both products and subcategories</td></tr><tr><td><code>products</code></td><td>Show only products</td></tr><tr><td><code>subcategories</code></td><td>Show only subcategory tiles</td></tr><tr><td><code>both</code></td><td>Show subcategories first, then products</td></tr></tbody></table><h2 id="custom-taxonomy-fields" tabindex="-1"><a class="header-anchor" href="#custom-taxonomy-fields"><span>Custom Taxonomy Fields</span></a></h2><p>For ACF, Yoast, or custom meta on categories:</p><div class="language-csv line-numbers-mode" data-highlighter="prismjs" data-ext="csv"><pre><code><span class="line"><span class="token value">Name</span><span class="token punctuation">,</span><span class="token value">Meta: category_banner</span><span class="token punctuation">,</span><span class="token value">_yoast_wpseo_title</span></span>\n<span class="line"><span class="token value">Men&#39;s Shirts</span><span class="token punctuation">,</span><span class="token value">https://example.com/banner.jpg</span><span class="token punctuation">,</span><span class="token value">Men&#39;s Shirts - Shop Now</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="sort-order" tabindex="-1"><a class="header-anchor" href="#sort-order"><span>Sort Order</span></a></h2><p>Set the order of categories in menus and product lists:</p><div class="language-csv line-numbers-mode" data-highlighter="prismjs" data-ext="csv"><pre><code><span class="line"><span class="token value">Name</span><span class="token punctuation">,</span><span class="token value">Sort Order</span></span>\n<span class="line"><span class="token value">Men&#39;s</span><span class="token punctuation">,</span><span class="token value">1</span></span>\n<span class="line"><span class="token value">Women&#39;s</span><span class="token punctuation">,</span><span class="token value">2</span></span>\n<span class="line"><span class="token value">Kids</span><span class="token punctuation">,</span><span class="token value">3</span></span>\n<span class="line"><span class="token value">Sale</span><span class="token punctuation">,</span><span class="token value">4</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Lower numbers appear first.</p><h2 id="updating-existing-categories" tabindex="-1"><a class="header-anchor" href="#updating-existing-categories"><span>Updating Existing Categories</span></a></h2><p>Use Match Key = <code>Slug</code> or <code>Name</code> in Update Only mode.</p><div class="language-csv line-numbers-mode" data-highlighter="prismjs" data-ext="csv"><pre><code><span class="line"><span class="token value">Name</span><span class="token punctuation">,</span><span class="token value">Description</span></span>\n<span class="line"><span class="token value">Men&#39;s T-Shirts</span><span class="token punctuation">,</span><span class="token value">Updated description for the men&#39;s tees category</span></span>\n<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="troubleshooting" tabindex="-1"><a class="header-anchor" href="#troubleshooting"><span>Troubleshooting</span></a></h2><table><thead><tr><th>Problem</th><th>Fix</th></tr></thead><tbody><tr><td>Categories created at top level instead of nested</td><td>Check your separator in Step 2 (default is <code>&gt;</code>)</td></tr><tr><td>Duplicate categories created</td><td>Slug matching is case-sensitive. Use Update mode with Slug match key</td></tr><tr><td>Images did not download</td><td>Check Settings → Image handling → Download Images is on</td></tr><tr><td>Tags not applied to products</td><td>Tags must be imported first, OR tags auto-create must be on in Step 3</td></tr><tr><td>Attribute term not showing</td><td>Attribute must exist first. Import attributes, then terms</td></tr></tbody></table><p><img src="/advance-import-export-woocommerce/images/wizard-step-5.webp" alt="Wizard step 5 — import results summary"><em>Results screen confirms how many categories, tags, or attribute terms were created or updated — and surfaces any slug conflicts to resolve.</em></p><h2 id="related-pages" tabindex="-1"><a class="header-anchor" href="#related-pages"><span>Related Pages</span></a></h2>',63)),(0,t.Lk)("ul",null,[(0,t.Lk)("li",null,[(0,t.bF)(s,{to:"/products-import.html"},{default:(0,t.k6)(()=>[...a[0]||(a[0]=[(0,t.eW)("Products Import",-1)])]),_:1}),a[1]||(a[1]=(0,t.eW)(" — Assign categories to products",-1))]),(0,t.Lk)("li",null,[(0,t.bF)(s,{to:"/column-mapping.html"},{default:(0,t.k6)(()=>[...a[2]||(a[2]=[(0,t.eW)("Column Mapping",-1)])]),_:1}),a[3]||(a[3]=(0,t.eW)(" — Map custom columns",-1))]),(0,t.Lk)("li",null,[(0,t.bF)(s,{to:"/import-modes.html"},{default:(0,t.k6)(()=>[...a[4]||(a[4]=[(0,t.eW)("Import Modes",-1)])]),_:1}),a[5]||(a[5]=(0,t.eW)(" — Create vs Update",-1))])])])}]]),r=JSON.parse('{"path":"/categories-import.html","title":"Categories and Tags Import","lang":"en-US","frontmatter":{"title":"Categories and Tags Import","description":"Import product categories (with hierarchy), tags, and attributes. Full field reference.","meta":[{"name":"keywords","content":"woocommerce category import, product tags csv, nested categories, taxonomy import, attributes import"}]},"headers":[{"level":2,"title":"Three Related Entity Types","slug":"three-related-entity-types","link":"#three-related-entity-types","children":[]},{"level":2,"title":"Categories","slug":"categories","link":"#categories","children":[{"level":3,"title":"Column Reference","slug":"column-reference","link":"#column-reference","children":[]},{"level":3,"title":"Full Path in One Column","slug":"full-path-in-one-column","link":"#full-path-in-one-column","children":[]},{"level":3,"title":"Change the Separator","slug":"change-the-separator","link":"#change-the-separator","children":[]},{"level":3,"title":"Auto-Create Missing Parents","slug":"auto-create-missing-parents","link":"#auto-create-missing-parents","children":[]}]},{"level":2,"title":"Tags","slug":"tags","link":"#tags","children":[{"level":3,"title":"Column Reference","slug":"column-reference-1","link":"#column-reference-1","children":[]},{"level":3,"title":"Multiple Tags per Product","slug":"multiple-tags-per-product","link":"#multiple-tags-per-product","children":[]}]},{"level":2,"title":"Attributes","slug":"attributes","link":"#attributes","children":[{"level":3,"title":"Creating Attributes","slug":"creating-attributes","link":"#creating-attributes","children":[]},{"level":3,"title":"Attribute Types","slug":"attribute-types","link":"#attribute-types","children":[]},{"level":3,"title":"Order By","slug":"order-by","link":"#order-by","children":[]},{"level":3,"title":"Has Archives","slug":"has-archives","link":"#has-archives","children":[]}]},{"level":2,"title":"Category Images","slug":"category-images","link":"#category-images","children":[{"level":3,"title":"Upload via URL","slug":"upload-via-url","link":"#upload-via-url","children":[]},{"level":3,"title":"Re-use Media Library","slug":"re-use-media-library","link":"#re-use-media-library","children":[]}]},{"level":2,"title":"Display Types","slug":"display-types","link":"#display-types","children":[]},{"level":2,"title":"Custom Taxonomy Fields","slug":"custom-taxonomy-fields","link":"#custom-taxonomy-fields","children":[]},{"level":2,"title":"Sort Order","slug":"sort-order","link":"#sort-order","children":[]},{"level":2,"title":"Updating Existing Categories","slug":"updating-existing-categories","link":"#updating-existing-categories","children":[]},{"level":2,"title":"Troubleshooting","slug":"troubleshooting","link":"#troubleshooting","children":[]},{"level":2,"title":"Related Pages","slug":"related-pages","link":"#related-pages","children":[]}],"git":{},"filePathRelative":"categories-import.md"}')}}]);